config.generatedSceneCode:
ctx.lineCap = 'round';
ctx.lineJoin = 'round';

var W = canvas.width, H = canvas.height;
var p = runtimeState.pointer || { x: -9999, y: -9999, down: false, clicked: false };
if (!runtimeState.params) runtimeState.params = {};
var params = runtimeState.params;

// Initialize blueprint variables
if (params.datasetType == null) params.datasetType = 0; // 0 linear, 1 overlap, 2 nonlinear
if (params.cValue == null) params.cValue = 1;
if (params.rbfGamma == null) params.rbfGamma = 1.5;
if (params.pointCount == null) params.pointCount = 35;
if (params.showLabels == null) params.showLabels = true;
if (params.showMargins == null) params.showMargins = true;
if (params.showSupportVectors == null) params.showSupportVectors = true;
if (params.showKernelView == null) params.showKernelView = false;
if (params.stepIndex == null) params.stepIndex = 0;

// Palette (light theme)
var C_BG_PANEL = 'rgba(250, 245, 235, 0.92)';
var C_BORDER = 'rgba(0,0,0,0.1)';
var C_TEXT = '#1e293b';
var C_MUTED = '#64748b';
var C_BLUE = '#2563eb';
var C_ORANGE = '#f97316';
var C_BOUNDARY = '#111827';
var C_SV = '#22c55e';
var C_GREEN = '#16A34A';
var C_RED = '#DC2626';

var pad = 18;
var plot = { x: 230, y: 80, w: Math.max(380, W - 500), h: Math.max(300, H - 170) };
if (plot.x + plot.w > W - 20) plot.w = W - plot.x - 20;
if (plot.y + plot.h > H - 20) plot.h = H - plot.y - 20;

function clamp(v, a, b){ return Math.max(a, Math.min(b, v)); }
function lerp(a,b,t){ return a + (b-a)*t; }
function inRect(mx,my,r){ return mx>=r.x && my>=r.y && mx<=r.x+r.w && my<=r.y+r.h; }
function drawRoundRect(x,y,w,h,r,fill,stroke){
  ctx.beginPath();
  ctx.moveTo(x+r,y);
  ctx.arcTo(x+w,y,x+w,y+h,r);
  ctx.arcTo(x+w,y+h,x,y+h,r);
  ctx.arcTo(x,y+h,x,y,r);
  ctx.arcTo(x,y,x+w,y,r);
  if (fill){ ctx.fillStyle = fill; ctx.fill(); }
  if (stroke){ ctx.strokeStyle = stroke; ctx.lineWidth = 1; ctx.stroke(); }
}
function wrapText(text,x,y,maxW,lineH,color,font){
  ctx.fillStyle = color; ctx.font = font; ctx.textAlign = 'left';
  var words = text.split(' '), line = '', yy = y;
  for (var i=0;i<words.length;i++){
    var test = line + words[i] + ' ';
    if (ctx.measureText(test).width > maxW && i>0){ ctx.fillText(line, x, yy); line = words[i] + ' '; yy += lineH; }
    else line = test;
  }
  ctx.fillText(line, x, yy);
  return yy;
}

// Deterministic synthetic datasets
var n = Math.round(params.pointCount);
var pts = [];
for (var i=0;i<n;i++){
  var t = i/(Math.max(1,n-1));
  if (params.datasetType === 0){
    var x1 = -2 + 1.7*t + 0.12*Math.sin(i*2.1);
    var y1 =  0.3 + 1.3*t + 0.15*Math.cos(i*1.7);
    var x2 =  0.4 + 1.6*t + 0.14*Math.cos(i*2.0);
    var y2 = -1.8 + 1.2*t + 0.12*Math.sin(i*1.9);
    pts.push({x:x1,y:y1,c:-1,id:'b'+i});
    pts.push({x:x2,y:y2,c: 1,id:'o'+i});
  } else if (params.datasetType === 1){
    var x1o = -1.8 + 2.2*t + 0.35*Math.sin(i*1.3);
    var y1o =  0.5 + 1.0*t + 0.35*Math.cos(i*1.9);
    var x2o = -0.1 + 2.0*t + 0.35*Math.cos(i*1.5);
    var y2o = -1.1 + 1.2*t + 0.35*Math.sin(i*2.2);
    pts.push({x:x1o,y:y1o,c:-1,id:'b'+i});
    pts.push({x:x2o,y:y2o,c: 1,id:'o'+i});
  } else {
    var ang = i * (Math.PI*2/n);
    var r1 = 0.9 + 0.08*Math.sin(i*2.3);
    var r2 = 2.0 + 0.1*Math.cos(i*1.7);
    pts.push({x:r1*Math.cos(ang), y:r1*Math.sin(ang), c:-1, id:'b'+i});
    pts.push({x:r2*Math.cos(ang+0.08), y:r2*Math.sin(ang+0.08), c:1, id:'o'+i});
  }
}

// Model proxy
var C = params.cValue;
var gamma = params.rbfGamma;
var w = {x: 1, y: -1};
var b = 0;
if (params.datasetType===0){ w={x:1,y:-1}; b=-0.05; }
if (params.datasetType===1){ w={x:1,y:-0.75}; b=-0.25 + 0.18*Math.log(C+1); }
var wnorm = Math.sqrt(w.x*w.x + w.y*w.y);
var baseMargin = 1/wnorm;
var margin = params.datasetType===1 ? clamp(baseMargin*(1.35 - 0.25*Math.log(C+1)), 0.45, 1.5) : baseMargin;

function toScreen(x,y){
  var xr = (x + 3)/6, yr = (y + 3)/6;
  return { x: plot.x + xr*plot.w, y: plot.y + (1-yr)*plot.h };
}

// Grid + axes
ctx.strokeStyle = 'rgba(100,116,139,0.22)'; ctx.lineWidth = 1;
for (var gx=0; gx<=6; gx++){
  var X = plot.x + gx*plot.w/6; ctx.beginPath(); ctx.moveTo(X,plot.y); ctx.lineTo(X,plot.y+plot.h); ctx.stroke();
}
for (var gy=0; gy<=6; gy++){
  var Y = plot.y + gy*plot.h/6; ctx.beginPath(); ctx.moveTo(plot.x,Y); ctx.lineTo(plot.x+plot.w,Y); ctx.stroke();
}
ctx.strokeStyle = 'rgba(17,24,39,0.6)';
var o1 = toScreen(0,-3), o2 = toScreen(0,3), o3 = toScreen(-3,0), o4 = toScreen(3,0);
ctx.beginPath(); ctx.moveTo(o1.x,o1.y); ctx.lineTo(o2.x,o2.y); ctx.stroke();
ctx.beginPath(); ctx.moveTo(o3.x,o3.y); ctx.lineTo(o4.x,o4.y); ctx.stroke();

// Decision boundary
function drawLineOffset(off, style, lw, dash){
  var pA, pB;
  if (Math.abs(w.y) < 1e-4){
    var x = -(b+off)/w.x; pA = toScreen(x,-3); pB = toScreen(x,3);
  } else {
    var yL = -(w.x*(-3)+b+off)/w.y;
    var yR = -(w.x*(3)+b+off)/w.y;
    pA = toScreen(-3,yL); pB = toScreen(3,yR);
  }
  ctx.save();
  if (dash) ctx.setLineDash(dash); else ctx.setLineDash([]);
  ctx.strokeStyle = style; ctx.lineWidth = lw;
  ctx.beginPath(); ctx.moveTo(pA.x,pA.y); ctx.lineTo(pB.x,pB.y); ctx.stroke();
  ctx.restore();
}

if (params.datasetType===2 && params.showKernelView){
  // Curved boundary for RBF view
  ctx.strokeStyle = C_BOUNDARY; ctx.lineWidth = 3;
  ctx.beginPath();
  for (var k=0;k<=180;k++){
    var a = (k/180)*Math.PI*2;
    var r = 1.45 + 0.18*Math.sin(a*3 + time*0.7) * (gamma/10);
    var q = toScreen(r*Math.cos(a), r*Math.sin(a));
    if (k===0) ctx.moveTo(q.x,q.y); else ctx.lineTo(q.x,q.y);
  }
  ctx.closePath(); ctx.stroke();
} else {
  drawLineOffset(0, C_BOUNDARY, 3, null);
  if (params.showMargins) {
    drawLineOffset(1*margin*wnorm, 'rgba(17,24,39,0.55)', 2, [6,6]);
    drawLineOffset(-1*margin*wnorm, 'rgba(17,24,39,0.55)', 2, [6,6]);
  }
}

// support vectors estimate
var sv = [];
var errors = 0;
for (var j=0;j<pts.length;j++){
  var pt = pts[j];
  var f = (params.datasetType===2 && params.showKernelView)
    ? ((pt.x*pt.x + pt.y*pt.y) - 1.45*1.45)
    : (w.x*pt.x + w.y*pt.y + b);
  var y = pt.c;
  var hinge = 1 - y*f;
  if (hinge > 0.08) sv.push(pt);
  if (y*f < 0) errors++;
}
var trainErr = errors / pts.length;

// Points
for (var m=0;m<pts.length;m++){
  var d = pts[m], s = toScreen(d.x,d.y);
  var isSV = params.showSupportVectors && sv.indexOf(d)>=0;
  var pulse = isSV ? (1 + 0.08*Math.sin(time*5 + m)) : 1;
  ctx.save();
  ctx.translate(s.x,s.y); ctx.scale(pulse,pulse);
  ctx.lineWidth = isSV ? 3 : 1.5;
  ctx.strokeStyle = isSV ? C_SV : 'rgba(15,23,42,0.45)';
  if (d.c<0){
    ctx.fillStyle = C_BLUE;
    ctx.beginPath(); ctx.arc(0,0,5.5,0,Math.PI*2); ctx.fill(); ctx.stroke();
  } else {
    ctx.fillStyle = C_ORANGE;
    ctx.beginPath(); ctx.moveTo(0,-6); ctx.lineTo(6,5); ctx.lineTo(-6,5); ctx.closePath(); ctx.fill(); ctx.stroke();
  }
  ctx.restore();
  if (isSV && params.showLabels){
    ctx.fillStyle = C_SV; ctx.font = '10px ui-monospace, monospace'; ctx.textAlign='left';
    ctx.fillText('SV', s.x+8, s.y-8);
  }
}

// Titles and axis labels
ctx.fillStyle = C_TEXT;
ctx.font = '600 20px system-ui, sans-serif';
ctx.textAlign = 'center';
ctx.fillText('How SVMs Find the Best Separator', W*0.5, 34);
ctx.textAlign = 'left';
ctx.font = '11px system-ui, sans-serif';
ctx.fillText('x1', plot.x+plot.w-14, toScreen(3,0).y-6);
ctx.fillText('x2', toScreen(0,0).x+6, plot.y+12);

// Annotations
ctx.fillStyle = C_MUTED; ctx.font = 'italic 14px Georgia, serif'; ctx.textAlign='left';
ctx.fillText('maximize margin', plot.x + 10, plot.y - 12);
ctx.fillText('support vectors define boundary', plot.x + 20, plot.y + plot.h + 20);
ctx.fillText('C trades margin vs errors', plot.x + plot.w - 210, plot.y + 20);

// Controls panel (top-left)
var panel = {x:16,y:16,w:190,h:290};
drawRoundRect(panel.x,panel.y,panel.w,panel.h,12,C_BG_PANEL,C_BORDER);
ctx.fillStyle = C_TEXT; ctx.textAlign='left';
ctx.font='10px system-ui, sans-serif'; ctx.fillText('CONTROLS', panel.x+14,panel.y+18);

function button(x,y,w,h,label,active){
  drawRoundRect(x,y,w,h,6, active? 'rgba(37,99,235,0.14)':'rgba(255,255,255,0.6)', C_BORDER);
  ctx.fillStyle = C_TEXT; ctx.font='11px system-ui, sans-serif'; ctx.textAlign='center';
  ctx.fillText(label, x+w/2, y+h/2+4);
  ctx.textAlign='left';
  return {x:x,y:y,w:w,h:h};
}

var y0 = panel.y+30;
ctx.fillStyle=C_MUTED; ctx.font='11px system-ui, sans-serif'; ctx.fillText('Dataset', panel.x+14,y0);
var b0 = button(panel.x+14,y0+8,52,24,'Linear',params.datasetType===0);
var b1 = button(panel.x+72,y0+8,96,24,'Slight overlap',params.datasetType===1);
var b2 = button(panel.x+14,y0+38,154,24,'Nonlinear (circles)',params.datasetType===2);
if (p.clicked && inRect(p.x,p.y,b0)) params.datasetType=0;
if (p.clicked && inRect(p.x,p.y,b1)) params.datasetType=1;
if (p.clicked && inRect(p.x,p.y,b2)) params.datasetType=2;

function toggleRow(label,key,yy){
  var r = button(panel.x+14,yy,154,22,label,!!params[key]);
  if (p.clicked && inRect(p.x,p.y,r)) params[key]=!params[key];
}
var ty = y0+72;
toggleRow('showLabels','showLabels',ty); ty+=28;
toggleRow('showMargins','showMargins',ty); ty+=28;
toggleRow('showSupportVectors','showSupportVectors',ty); ty+=28;
toggleRow('showKernelView','showKernelView',ty);

function slider(label,key,min,max,yy){
  ctx.fillStyle=C_MUTED; ctx.font='11px system-ui, sans-serif'; ctx.textAlign='left';
  ctx.fillText(label, panel.x+14, yy);
  var tx=panel.x+14, tw=154, th=6, tyy=yy+8;
  drawRoundRect(tx,tyy,tw,th,4,'rgba(148,163,184,0.35)',null);
  var t = (params[key]-min)/(max-min); t=clamp(t,0,1);
  drawRoundRect(tx,tyy,tw*t,th,4,'rgba(37,99,235,0.8)',null);
  var hx=tx+tw*t;
  ctx.beginPath(); ctx.arc(hx,tyy+th/2,6,0,Math.PI*2); ctx.fillStyle='#fff'; ctx.fill(); ctx.strokeStyle='rgba(37,99,235,0.9)'; ctx.lineWidth=2; ctx.stroke();
  if (p.down && p.x>=tx-8 && p.x<=tx+tw+8 && p.y>=tyy-8 && p.y<=tyy+th+8){
    var nt = clamp((p.x-tx)/tw,0,1); params[key] = min + nt*(max-min);
  }
  ctx.fillStyle=C_TEXT; ctx.font='700 11px ui-monospace, monospace'; ctx.fillText((Math.round(params[key]*100)/100).toString(), tx+tw-34, yy);
}
slider('Soft-margin C','cValue',0.1,50,panel.y+240);

// Kernel gamma and point count bottom-center
var bottom = {x: W*0.5-170, y:H-74, w:340, h:58};
drawRoundRect(bottom.x,bottom.y,bottom.w,bottom.h,12,C_BG_PANEL,C_BORDER);
slider('RBF γ','rbfGamma',0.1,10,bottom.y+18);
// pointCount compact
var pcx=bottom.x+190, pcy=bottom.y+18;
ctx.fillStyle=C_MUTED; ctx.font='11px system-ui, sans-serif'; ctx.textAlign='left'; ctx.fillText('Points/class', pcx,pcy);
var tr={x:pcx,y:pcy+8,w:130,h:6}; drawRoundRect(tr.x,tr.y,tr.w,tr.h,4,'rgba(148,163,184,0.35)',null);
var tt=(params.pointCount-10)/70; tt=clamp(tt,0,1); drawRoundRect(tr.x,tr.y,tr.w*tt,tr.h,4,'rgba(37,99,235,0.8)',null);
ctx.beginPath(); ctx.arc(tr.x+tr.w*tt,tr.y+3,6,0,Math.PI*2); ctx.fillStyle='#fff'; ctx.fill(); ctx.strokeStyle='rgba(37,99,235,0.9)'; ctx.lineWidth=2; ctx.stroke();
if (p.down && p.x>=tr.x-8 && p.x<=tr.x+tr.w+8 && p.y>=tr.y-8 && p.y<=tr.y+tr.h+8){ params.pointCount = Math.round(10 + clamp((p.x-tr.x)/tr.w,0,1)*70); }
ctx.fillStyle=C_TEXT; ctx.font='700 11px ui-monospace, monospace'; ctx.fillText(String(Math.round(params.pointCount)), tr.x+tr.w-28,pcy);

// Metrics panel
var met={x:16,y:316,w:190,h:124};
drawRoundRect(met.x,met.y,met.w,met.h,12,C_BG_PANEL,C_BORDER);
ctx.fillStyle=C_TEXT; ctx.font='10px system-ui, sans-serif'; ctx.textAlign='left'; ctx.fillText('LIVE METRICS',met.x+14,met.y+18);
ctx.font='700 12px ui-monospace, monospace';
ctx.fillText('margin width: '+(Math.round((2*margin)*100)/100),met.x+14,met.y+40);
ctx.fillText('# support vec: '+sv.length,met.x+14,met.y+60);
ctx.fillText('training error: '+(Math.round(trainErr*1000)/10)+'%',met.x+14,met.y+80);
ctx.fillText('C: '+(Math.round(C*100)/100),met.x+14,met.y+100);

// SCAFFOLD STEP 1: Keep dataset on Linear. Toggle showMargins ON and observe the widest-margin separator.
// SCAFFOLD STEP 2: Toggle showSupportVectors ON and read the labels on the highlighted points.
// SCAFFOLD STEP 3: Switch dataset to Slight overlap. Adjust C from low to high while watching margin width and errors.
// SCAFFOLD STEP 4: Switch dataset to Nonlinear (circles). Turn showKernelView ON and observe curved boundary.
// SCAFFOLD STEP 5: In nonlinear dataset, adjust RBF γ and watch boundary complexity/support vectors.
var steps = [
  { instruction:'Keep dataset on Linear. Toggle showMargins ON and observe the widest-margin separator.', concept:'SVM aims to maximize margin among all separating lines.', done:(params.datasetType===0 && params.showMargins===true) },
  { instruction:'Toggle showSupportVectors ON and read the labels on the highlighted points.', concept:'Only the closest points (support vectors) determine the boundary and margins.', done:(params.showSupportVectors===true) },
  { instruction:'Switch dataset to Slight overlap. Adjust C from low to high while watching margin width and errors.', concept:'C trades margin vs errors: low C allows more violations; high C penalizes errors and often narrows margin.', done:(params.datasetType===1 && params.cValue>=10) },
  { instruction:'Switch dataset to Nonlinear (circles). Turn showKernelView ON and observe the curved boundary.', concept:'Kernels enable nonlinear boundaries without manual feature engineering.', done:(params.datasetType===2 && params.showKernelView===true) },
  { instruction:'In nonlinear dataset, adjust RBF γ and watch boundary complexity and support vectors.', concept:'Kernel parameters control flexibility; higher γ can produce more complex boundaries.', done:(params.datasetType===2 && params.rbfGamma>=5) }
];
params.stepIndex = clamp(Math.round(params.stepIndex),0,steps.length-1);
var st = steps[params.stepIndex];

var sp={x:W-300,y:16,w:284,h:230};
drawRoundRect(sp.x,sp.y,sp.w,sp.h,12,C_BG_PANEL,C_BORDER);
ctx.fillStyle=C_TEXT; ctx.textAlign='left'; ctx.font='10px system-ui, sans-serif'; ctx.fillText('SCAFFOLDED STEPS',sp.x+14,sp.y+18);
ctx.fillStyle=C_MUTED; ctx.font='11px system-ui, sans-serif'; ctx.fillText('Step '+(params.stepIndex+1)+' / '+steps.length,sp.x+14,sp.y+36);
ctx.fillStyle=C_TEXT; wrapText('INSTRUCTION: '+st.instruction,sp.x+14,sp.y+56,sp.w-28,16,C_TEXT,'700 11px system-ui, sans-serif');
wrapText('Concept: '+st.concept,sp.x+14,sp.y+126,sp.w-28,18,C_MUTED,'italic 14px Georgia, serif');
ctx.font='700 12px ui-monospace, monospace'; ctx.fillStyle=st.done?C_GREEN:C_RED; ctx.textAlign='left'; ctx.fillText(st.done?'Condition met':'Condition not met',sp.x+14,sp.y+186);
var lbtn={x:sp.x+14,y:sp.y+196,w:34,h:24}, rbtn={x:sp.x+56,y:sp.y+196,w:34,h:24};
button(lbtn.x,lbtn.y,lbtn.w,lbtn.h,'←',false); button(rbtn.x,rbtn.y,rbtn.w,rbtn.h,'→',false);
if (p.clicked && inRect(p.x,p.y,lbtn)) params.stepIndex = clamp(params.stepIndex-1,0,steps.length-1);
if (p.clicked && inRect(p.x,p.y,rbtn)) params.stepIndex = clamp(params.stepIndex+1,0,steps.length-1);

// Kernel inset schematic
if (params.datasetType===2 && params.showKernelView){
  var inset={x:W-300,y:254,w:284,h:140};
  drawRoundRect(inset.x,inset.y,inset.w,inset.h,12,C_BG_PANEL,C_BORDER);
  ctx.fillStyle=C_TEXT; ctx.font='10px system-ui, sans-serif'; ctx.textAlign='left'; ctx.fillText('KERNEL VIEW (SCHEMATIC)',inset.x+14,inset.y+18);
  ctx.strokeStyle='rgba(100,116,139,0.4)'; ctx.lineWidth=1;
  ctx.beginPath(); ctx.arc(inset.x+80,inset.y+80,26,0,Math.PI*2); ctx.stroke();
  ctx.beginPath(); ctx.arc(inset.x+80,inset.y+80,52,0,Math.PI*2); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(inset.x+150,inset.y+36); ctx.lineTo(inset.x+150,inset.y+118); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(inset.x+150,inset.y+76); ctx.lineTo(inset.x+258,inset.y+76); ctx.strokeStyle=C_BOUNDARY; ctx.lineWidth=2.5; ctx.stroke();
  ctx.fillStyle=C_MUTED; ctx.font='11px system-ui, sans-serif';
  ctx.fillText('input space', inset.x+26,inset.y+126);
  ctx.fillText('lifted feature space', inset.x+156,inset.y+126);
}
